(self.webpackChunkvuepress_blog=self.webpackChunkvuepress_blog||[]).push([[26],{3021:(e,l,i)=>{"use strict";i.r(l),i.d(l,{data:()=>s});const s={key:"v-4e93940c",path:"/pages/fe-interview/project-interview/",title:"",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[{level:3,title:"前期准备",slug:"前期准备",children:[]},{level:3,title:"面试介绍文案",slug:"面试介绍文案",children:[]},{level:3,title:"项目难点",slug:"项目难点",children:[]},{level:3,title:"jscodeshift",slug:"jscodeshift",children:[]},{level:3,title:"polyfill-service",slug:"polyfill-service",children:[]},{level:3,title:"主子应用迁移 流程与运行机理",slug:"主子应用迁移-流程与运行机理",children:[]},{level:3,title:"简历知识点汇总",slug:"简历知识点汇总",children:[]}],filePathRelative:"pages/fe-interview/project-interview/README.md",git:{updatedTime:1744962886e3,contributors:[{name:"COOKIES-LGL",email:"1344714332@qq.com",commits:8}]}}},6502:(e,l,i)=>{"use strict";i.r(l),i.d(l,{default:()=>r});const s=(0,i(6252).uE)('<h3 id="前期准备"><a class="header-anchor" href="#前期准备">#</a> 前期准备</h3><ul><li>八股文、</li><li>算法、</li><li>常见 coding、</li><li>项目总结、</li><li>前端新技术拓展。</li></ul><h3 id="面试介绍文案"><a class="header-anchor" href="#面试介绍文案">#</a> 面试介绍文案</h3><p>面试官你好，我叫李贵霖，20 年毕业于江南大学计算机科学与技术专业，然后校招进入 SHOPEE seller 部门担任前端开发工程师， 主要负责卖家教育、卖家入驻、卖家保证金健康度管理、等业务的开发工作。22 年来到拼多多，在拼多多先后待了两个业务组，一个是 特木 的基础电商业务组 一个是 特木 跨境结算。在基础电商部门的时候参与了用户增长达人邀约项目搭建，特木 App 内部新人转化活动页全额返和一折购的开发工作。 在跨境结算部门负责一个微服务项目内的人力结算业务的业务开发，涉及人力成本、劳务仓内处罚、仓作业计费管理等，也有涉及卖家履约服务，等卖家管理。</p><p>达人邀约项目 项目涉及 H5 端和 PC 端，前端部署了两份服务端渲染的代码，通过在网关处拦截用户的 userAgent 来判断访问 PC 端还是 H5 端。</p><p>首页弹窗管理 首先维护了一个弹窗队列，保存了首屏会出现的所有弹窗，数组的每一项是一个对象保存了弹窗组件，弹窗展示条件，弹窗关闭回调，然后根据用户状态， filter 需要展示的弹窗队列，在首页递归展示。</p><p>场景数据 MOCK 由于我们的接口数据 mock 是单个接口拦截处理的，接口是没有副作用的， 接口与接口之间是不相关的，所以涉及到接口有副作用，接口与接口之间相互影响的时候 就无法 mock 了。所以就弄了一个场景值 mock 函数，主要原理就是一开始在各个接口内调用函数注册场景值，然后这里面有一个接口是驱动者， 这个接口的调用次数来驱动场景值往下一个场景值切换。给场景值定义一个唯一标识为 key，当前场景为值绑定到 global 上，这样这个场景值可以在多个接口之间共享。</p><h3 id="项目难点"><a class="header-anchor" href="#项目难点">#</a> 项目难点</h3><p>script 加载 js 走服务器响应的缓存策略。 fetch 加载 js 如果请求 header 有缓存策略会影响到响应的缓存策略。 但请求头的设置确实可以影响缓存的使用方式和策略。如果请求头设置了 Cache-Control: no-cache，即使响应头指示资源可以被缓存，客户端也可能会选择不直接使用缓存的响应，而是向服务器发送请求进行验证 ‌</p><h3 id="jscodeshift"><a class="header-anchor" href="#jscodeshift">#</a> jscodeshift</h3><h3 id="polyfill-service"><a class="header-anchor" href="#polyfill-service">#</a> polyfill-service</h3><h3 id="主子应用迁移-流程与运行机理"><a class="header-anchor" href="#主子应用迁移-流程与运行机理">#</a> 主子应用迁移 流程与运行机理</h3><h3 id="简历知识点汇总"><a class="header-anchor" href="#简历知识点汇总">#</a> 简历知识点汇总</h3><p>1、vue ssr 改造 2、内存泄露问题排查流程 3、站点 SEO 流程 4、大文件分片上传、断点续传 5、六方格、大圈盘活动页开发要点 6、webpack5、新特性 7、webpack 优化 8、eslint stylelint 自定义规则编写 9、PAP 项目理解</p>',14),r={render:function(e,l){return s}}}}]);